# ANTI-PATTERN: Regenerating context embeddings for every query
class PoorBowlingStrategy:
    def respond_to_batsman_query(self, query, match_history):
        # ❌ Recomputing embeddings every time (wasteful)
        context_embedding = self.embed(match_history)  # O(|history|) every call
        response = self.model.generate(query, context_embedding)
        return response

# BEST PRACTICE: Cache static context, reuse across queries
class OptimizedBowlingStrategy:
    def __init__(self, match_history):
        # ✅ Embed once, reuse for multiple queries
        self.cached_context = self.embed(match_history)  # O(|history|) once

    def respond_to_batsman_query(self, query):
        # Reuse cached embeddings for every query
        response = self.model.generate_with_cache(query, self.cached_context)
        return response

# ANTI-PATTERN: Ignoring retrieval ranking quality
class UncontrolledRAG:
    def answer_cricket_question(self, query):
        # ❌ Takes first 5 documents regardless of relevance
        docs = self.retriever.search(query, top_k=5)
        return self.model.generate(query, context=docs)  # Hallucination risk if docs are irrelevant

# BEST PRACTICE: Validate retrieval quality before feeding to LLM
class RobustRAG:
    def answer_cricket_question(self, query):
        # ✅ Ranks by relevance, filters low-confidence matches
        docs = self.retriever.search(query, top_k=20)
        filtered_docs = [d for d in docs if d.similarity_score > 0.7]  # Confidence threshold
        if not filtered_docs:
            return "Insufficient reliable sources; match statistics unavailable."
        return self.model.generate(query, context=filtered_docs[:5])
